sql:
SELECT test_conductor, AVG(scr_score + fac_score + lon_score + eff_score + d_score) AS average_total_score
FROM survey_scores
GROUP BY test_conductor;

SELECT AVG(f6_score)
FROM survey_scores
WHERE test_date = '2023-02-10';

SELECT participant_id, f1_score
FROM survey_scores
WHERE f1_score < (SELECT AVG(f1_score) FROM survey_scores);

SELECT fac_score, lon_score
FROM survey_scores
ORDER BY fac_score DESC, lon_score DESC;

SELECT score_id, participant_id
FROM survey_scores
WHERE scr_score > 30;

SELECT COUNT(DISTINCT participant_id) AS scr_test_participants
FROM survey_scores
WHERE scr_score IS NOT NULL;

external_knowledge:
Average performance for the cognitive test scores is considered to be at or above 50 points;
The cognitive assessments involve both SCR and FAC tests;
Date of tests refers to when these assessments were conducted.

sql:
SELECT participant_id, f1_score AS Highest_Score
FROM survey_scores
WHERE f1_score = (SELECT MAX(f1_score) FROM survey_scores);
